import styles from './styles.module.scss';
import Image from 'next/image';
import Link from 'next/link';
import QuenMatKhau from './QuenMatKhau/page';

export default function DangNhap() {
  return (
    <div className={styles["outside-container"]}>
      <div className={styles["login-container"]}>
      <Link href="/" className={styles["back-button"]}>
          <span className={styles["arrow"]}>←</span>Quay lại
        </Link>

        <h1>Đăng Nhập</h1>
        <div className={styles["social-buttons"]}>
          <button className={styles["facebook-button"]}>
            <Image
              src="/Facebook.svg"
              alt="Facebook Login"
              width={32}
              height={32}
            />
            <span>Tiếp tục với Facebook</span>
          </button>
          <button className={styles["google-button"]}>
            <Image
              src="/Google.svg"
              alt="Google Login"
              width={32}
              height={32}
            />
            <span>Đăng nhập với Google</span>
          </button>
        </div>
        <div className={styles["separator"]}>
          <span>Hoặc</span>
        </div>
        <form action="#" method="post" className={styles["login-form"]}>
          <div className={styles["form-group"]}>
            <input type="text" id="username" name="username" placeholder=" " />
            <label htmlFor="username">
              Tài khoản / Số điện thoại / Email
            </label>
          </div>
          <div className={styles["form-group"]}>
            <input type="password" id="password" name="password" placeholder=" " />
            <label htmlFor="password">Mật khẩu</label>
          </div>
          <div className={styles["remember-me"]}>
            <input type="checkbox" id="remember" name="remember" />
            <label htmlFor="remember">Nhớ đăng nhập</label>
          </div>

          <div className={styles["button-group"]}>
            <button type="submit" className={styles["login-button"]}>
              Đăng nhập
            </button>
            <button type="button" className={styles["register-button"]}>
              Đăng ký
            </button>
          </div>
        </form>
        <div className={styles["forgot-password"]}>
          <Link href={QuenMatKhau}>Quên mật khẩu?</Link>
        </div>
      </div>
    </div>
  );
}