import styles from './styles.module.scss';
import Image from 'next/image';
import Link from 'next/link';

export default function QuenMatKhau() {
  return (
    <div className={styles["outside-container"]}>
      <div className={styles["login-container"]}>
        <Link href="/" className={styles["back-button"]}>
          <span className={styles["arrow"]}>←</span>Quay lại
        </Link>

        <h1>Quên Mật Khẩu</h1>
        <div className={styles["social-buttons"]}>
          <button className={styles["facebook-button"]}>
            <Image
              src="/Facebook.svg"
              alt="Facebook Login"
              width={32}
              height={32}
            />
            <span>Tiếp tục với Facebook</span>
          </button>
          <button className={styles["google-button"]}>
            <Image
              src="/Google.svg"
              alt="Google Login"
              width={32}
              height={32}
            />
            <span>Đăng nhập với Google</span>
          </button>
        </div>

        <div className={styles["separator"]}>
          <span>Hoặc</span>
        </div>

        <form action="#" method="post" className={styles["login-form"]}>
          <div className={styles["form-group"]}>
            <input type="email" id="email" name="email" placeholder=" " />
            <label htmlFor="email">Gmail</label>
          </div>

          <div className={styles["button-group"]}>
            <button type="submit" className={styles["register-button"]}>
              Quên Mật Khẩu
            </button>
          </div>
        </form>

        <div className={styles["auth-links"]}>
          <Link href="/DangKy" className={styles["register-button"]}>
            Đăng Ký
          </Link>
          <Link href="/DangNhap" className={styles["login-button"]}>
            Đăng Nhập
          </Link>
        </div>
      </div>
    </div>
  );
}